// v5.6.0: searchable catalog picker. A custom dropdown (not a native <select>,
// which can't be fully styled across browsers — its option text rendered blue on
// click). Filters CHECK_CATALOG by label/category/name/param; picking fills the
// form. Showing on focus is wired in openCustomChecks.
function ccCatalogSearch() {
  const box = document.getElementById('cc-catalog-results');
  if (!box) return;
  const term = (document.getElementById('cc-catalog-search')?.value || '').toLowerCase().trim();
  const hits = CHECK_CATALOG
    .map((e, i) => ({ e, i }))
    .filter(({ e }) => !term || (`${e.l} ${e.c} ${e.n} ${e.p}`).toLowerCase().includes(term))
    .slice(0, 80);
  box.innerHTML = hits.length
    ? hits.map(({ e, i }) => `<div class="dev-combo-item" data-action="ccPickCatalog" data-arg="${i}"><strong>${escHtml(e.l)}</strong> <span class="hint">${escHtml(e.c)}</span></div>`).join('')
    : '<div class="dev-combo-empty">No matching checks.</div>';
  box.hidden = false;
}
function ccPickCatalog(i) {
  const e = CHECK_CATALOG[typeof i === 'number' ? i : parseInt(i, 10)];
  const box = document.getElementById('cc-catalog-results'); if (box) box.hidden = true;
  if (!e) return;
  const setv = (id, v) => { const el = document.getElementById(id); if (el) el.value = v; };
  setv('cc-catalog-search', e.l);
  setv('cc-type', e.t);
  ccTypeChanged();   // refresh param label + sub-field visibility for the new type
  setv('cc-param', e.p);
  setv('cc-name', e.n);
}
// Host target is a device search typeahead (omnisearch), never a raw id field.
async function ccHostSearch() {
  const box = document.getElementById('cc-host-results');
  if (!box) return;
  const term = (document.getElementById('cc-host-search')?.value || '').toLowerCase().trim();
  const devs = await _scanDeviceList();
  let matches = Array.isArray(devs) ? devs : [];
  if (term) matches = matches.filter(d =>
    (d.name || '').toLowerCase().includes(term) || (d.ip || '').toLowerCase().includes(term) ||
    (d.group || '').toLowerCase().includes(term) || (d.tags || []).some(t => (t || '').toLowerCase().includes(term)));
  matches = matches.slice(0, 25);
  box.innerHTML = matches.length
    ? matches.map(d => `<div class="dev-combo-item" data-action="pickCcHost" data-arg="${escAttr(d.id)}" data-arg2="${escAttr(d.name || d.id)}">${escHtml(d.name || d.id)}${d.ip ? ` <span class="hint">${escHtml(d.ip)}</span>` : ''}</div>`).join('')
    : '<div class="dev-combo-empty">No matching devices.</div>';
  box.hidden = false;
}
function pickCcHost(id, name) {
  const t = document.getElementById('cc-target'); if (t) t.value = id;
  const s = document.getElementById('cc-host-search'); if (s) s.value = name;
  const box = document.getElementById('cc-host-results'); if (box) box.hidden = true;
}
function ccKindChanged() {
  const kind = document.getElementById('cc-kind')?.value || 'all';
  document.getElementById('cc-target-grp')?.classList.toggle('hidden', kind === 'all');
  const lbl = document.getElementById('cc-target-label');
  const inp = document.getElementById('cc-target');
  const pick = document.getElementById('cc-host-pick');
  const isHost = kind === 'host';
  if (lbl) lbl.textContent = isHost ? 'Device' : kind === 'tag' ? 'Tag' : 'Group';
  // A host target is ALWAYS a device search typeahead (never type a raw id);
  // tag/group keep the plain text input.
  if (inp) {
    inp.classList.toggle('hidden', isHost);
    inp.placeholder = kind === 'tag' ? 'tag name' : 'group name';
  }
  if (pick) pick.classList.toggle('hidden', !isHost);
}
function ccTypeChanged() {
  const t = document.getElementById('cc-type')?.value || 'process';
  const lbl = document.getElementById('cc-param-label');
  if (lbl) lbl.textContent = _CC_PARAM_LABELS[t] || 'Value';
  const inp = document.getElementById('cc-param');
  if (inp) inp.placeholder = _CC_PARAM_PH[t] || '';
  document.getElementById('cc-log-grp')?.classList.toggle('hidden', t !== 'log_errors');
  document.getElementById('cc-job-grp')?.classList.toggle('hidden', t !== 'job_fresh');
  // systemd_unit / windows_service: offer to also watch it on the Services page.
  document.getElementById('cc-svc-grp')?.classList.toggle(
    'hidden', t !== 'systemd_unit' && t !== 'windows_service');
}
let _ccCache = [];
let _ccEditId = null;
let _ccDevNames = {};   // device id -> hostname, for the saved-checks list + edit
function _ccResetForm() {
  _ccEditId = null;
  ['cc-name', 'cc-param', 'cc-target', 'cc-host-search', 'cc-catalog-search', 'cc-window', 'cc-warn', 'cc-crit', 'cc-unit', 'cc-maxage']
    .forEach(id => { const e = document.getElementById(id); if (e) e.value = ''; });
  const ws = document.getElementById('cc-watch-svc'); if (ws) ws.checked = true;
  ['cc-host-results', 'cc-catalog-results'].forEach(id => { const r = document.getElementById(id); if (r) r.hidden = true; });
  const k = document.getElementById('cc-kind'); if (k) k.value = 'all';
  const t = document.getElementById('cc-type'); if (t) t.value = 'process';
  const b = document.getElementById('cc-save-btn'); if (b) b.textContent = 'Add check';
  ccKindChanged(); ccTypeChanged();
}
async function openCustomChecks() {
  _ccResetForm();
  // show the dropdown lists when the search boxes get focus (CSP-safe listeners,
  // wired once per element)
  [['cc-catalog-search', ccCatalogSearch], ['cc-host-search', ccHostSearch]].forEach(([id, fn]) => {
    const el = document.getElementById(id);
    if (el && !el._wiredFocus) { el._wiredFocus = 1; el.addEventListener('focus', fn); }
  });
  openModal('custom-checks-modal');
  loadCustomCheckList();
}

// ── v6.2.3: Baseline checks — apply a recommended catalog set to a scope ──────
let _bcCatalog = [];
async function openBaselineChecks() {
  const el = document.getElementById('bc-catalog');
  if (el) el.innerHTML = '<div class="empty-state">Loading…</div>';
  const r = document.getElementById('bc-result'); if (r) r.textContent = '';
  const k = document.getElementById('bc-kind'); if (k) k.value = 'all';
  bcKindChanged();
  openModal('baseline-checks-modal');
  const data = await api('GET', '/checks/baseline-catalog');
  _bcCatalog = (data && data.catalog) || [];
  _bcRenderCatalog();
}
function bcKindChanged() {
  const k = document.getElementById('bc-kind')?.value || 'all';
  document.getElementById('bc-target-grp')?.classList.toggle('hidden', k === 'all');
}
function _bcRenderCatalog() {
  const el = document.getElementById('bc-catalog');
  if (!el) return;
  if (!_bcCatalog.length) { el.innerHTML = '<div class="empty-state">No catalog available.</div>'; return; }
  const cats = {};
  _bcCatalog.forEach(t => { (cats[t.cat] = cats[t.cat] || []).push(t); });
  el.innerHTML = Object.keys(cats).map(cat =>
    `<div class="section-title mt-8">${escHtml(cat)}</div>` +
    cats[cat].map(t =>
      `<label class="click-row-mb6"><input type="checkbox" class="bc-chk" value="${escAttr(t.id)}"> ` +
      `<strong>${escHtml(t.name)}</strong> <span class="meta-sm">${escHtml(t.type)}` +
      `${t.target_kind ? ' · tag:' + escHtml(t.target || '') : ''}</span>` +
      `<div class="meta-sm c-muted">${escHtml(t.desc || '')}</div></label>`
    ).join('')
  ).join('');
}
async function applyBaselineChecks() {
  const ids = Array.from(document.querySelectorAll('#bc-catalog .bc-chk:checked')).map(c => c.value);
  if (!ids.length) { toast('Select at least one check', 'error'); return; }
  const tk = document.getElementById('bc-kind')?.value || 'all';
  const tv = (document.getElementById('bc-target')?.value || '').trim();
  if (tk !== 'all' && !tv) { toast('Enter a ' + tk + ' name', 'error'); return; }
  const r = await api('POST', '/checks/baseline-apply', { ids, target_kind: tk, target: tv });
  if (r && r.ok) {
    toast(`Applied — ${r.added} check(s) added${r.added === 0 ? ' (already present)' : ''}`, 'success');
    closeModal('baseline-checks-modal');
    if (typeof loadChecks === 'function') loadChecks();
  } else toast((r && r.error) || 'Failed', 'error');
}

async function loadCustomCheckList() {
  const el = document.getElementById('cc-list');
  if (!el) return;
  const data = await api('GET', '/checks/custom');
  const checks = (data && data.checks) || [];
  _ccCache = checks;
  // Resolve host device ids -> hostnames for display (never show the raw id).
  try {
    const devs = await _scanDeviceList();
    _ccDevNames = {};
    (devs || []).forEach(d => { _ccDevNames[d.id] = d.name || d.id; });
  } catch (_) { /* keep whatever we had */ }
  if (!checks.length) { el.innerHTML = '<div class="empty-state">No custom checks yet.</div>'; return; }
  const scope = c => c.target_kind === 'all' ? 'whole fleet'
    : c.target_kind === 'host' ? `host: ${escHtml(_ccDevNames[c.target] || c.target)}`
    : `${c.target_kind}: ${escHtml(c.target)}`;
  const editBtn = id => `<button class="btn-icon btn-xs" data-action="editCustomCheck" data-arg="${escAttr(id)}" title="Edit this check">${_icon('edit',14)}</button>`;
  el.innerHTML = `<div class="table-card"><table><thead><tr><th>Name</th><th>Type</th><th>Param</th><th>Applies to</th><th></th></tr></thead><tbody>${
    checks.map(c => `<tr><td class="fw-500">${escHtml(c.name)}</td><td><span class="patch-badge ok fs-11">${escHtml(c.type)}</span></td><td class="mono-12">${escHtml(c.param)}</td><td class="hint">${scope(c)}</td><td><div class="user-actions">${editBtn(c.id)}<button class="btn-icon btn-xs c-danger-outline" title="Delete" data-action="deleteCustomCheck" data-arg="${escAttr(c.id)}">${_icon('trash',14)}</button></div></td></tr>`).join('')
  }</tbody></table></div>`;
}
function editCustomCheck(id) {
  const c = (_ccCache || []).find(x => x.id === id);
  if (!c) { toast('Check not found', 'error'); return; }
  _ccEditId = id;
  const setv = (eid, v) => { const e = document.getElementById(eid); if (e) e.value = (v === undefined || v === null) ? '' : v; };
  setv('cc-name', c.name); setv('cc-type', c.type || 'process'); setv('cc-param', c.param);
  setv('cc-kind', c.target_kind || 'all'); setv('cc-target', c.target);
  // host targets: show the device's HOSTNAME (not the raw id) in the search field
  if ((c.target_kind || 'all') === 'host') setv('cc-host-search', _ccDevNames[c.target] || c.target);
  setv('cc-window', c.window_min); setv('cc-warn', c.warn); setv('cc-crit', c.crit);
  setv('cc-unit', c.unit); setv('cc-maxage', c.max_age_hours);
  ccKindChanged(); ccTypeChanged();
  const b = document.getElementById('cc-save-btn'); if (b) b.textContent = 'Save changes';
  const nm = document.getElementById('cc-name'); if (nm) nm.focus();
}
async function saveCustomCheck() {
  const body = {
    name: document.getElementById('cc-name')?.value.trim() || '',
    type: document.getElementById('cc-type')?.value || 'process',
    param: document.getElementById('cc-param')?.value.trim() || '',
    target_kind: document.getElementById('cc-kind')?.value || 'all',
    target: document.getElementById('cc-target')?.value.trim() || '',
  };
  if (_ccEditId) body.id = _ccEditId;   // update-in-place keyed on id
  if (!body.param) { toast('A value is required', 'error'); return; }
  const numOf = id => { const v = parseInt(document.getElementById(id)?.value, 10); return isNaN(v) ? undefined : v; };
  if (body.type === 'log_errors') {
    body.window_min = numOf('cc-window');
    body.warn = numOf('cc-warn');
    body.crit = numOf('cc-crit');
    body.unit = document.getElementById('cc-unit')?.value.trim() || '';
  } else if (body.type === 'job_fresh') {
    body.max_age_hours = numOf('cc-maxage');
  } else if (body.type === 'systemd_unit' && body.target_kind === 'host') {
    // wire to the Services page: also watch this unit on the targeted host
    body.watch_service = !!document.getElementById('cc-watch-svc')?.checked;
  }
  const r = await api('POST', '/checks/custom', body);
  if (r && r.ok) {
    toast(_ccEditId ? 'Custom check saved' : 'Custom check added', 'success');
    _ccResetForm();
    loadCustomCheckList();
  } else { toast((r && r.error) || 'Failed', 'error'); }
}
async function deleteCustomCheck(id) {
  const r = await api('POST', '/checks/custom/delete', {id});
  if (r && r.ok) { loadCustomCheckList(); } else { toast((r && r.error) || 'Failed', 'error'); }
}
